console.log('Valid form errors:', JSON.stringify(errors));
console.log('Is valid:', Object.keys(errors).length === 0);

// Test invalid input
errors = validateForm({ name: '', email: 'invalid' });
console.log('Invalid form errors:', JSON.stringify(errors));
console.log('Is valid:', Object.keys(errors).length === 0);

